  ('heelevel3-53250add-moex-00142', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '法律行為標的必須符合一定之要件，始得發生法律上之效力，下列何者不屬之？', '["可能", "安全", "妥當", "合法 32820、33320 33620"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00143', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲以電話詢問乙書店有無甲欲購買之A書，乙表示「有」，甲即以市價新臺幣500元與乙訂立A書買 賣契約，並請乙保留該書，乙請甲可隨時到店裡拿書。數日後，甲至乙書店取書時，乙遍尋不著 該書。下列敘述，何者正確？', '["乙所負交付書籍之債務為有確定期限之債務", "甲赴書店而未能取得該書時，乙即負遲延責任", "甲請求交付書籍僅有催告效力，乙尚不負遲延責任", "甲欲購書籍如為種類物，甲不得解除契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00144', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲駕駛計程車載客人乙，途中不慎撞傷路人丙，導致丙住院支出醫療費、看護費等新臺幣10萬元。 丙請求甲、乙二人連帶負損害賠償責任，下列敘述，何者正確？', '["甲是乙之受僱人，乙應與甲連帶負損害賠償責任", "甲是乙之承攬人，乙原則上不須負損害賠償責任", "甲是乙之受任人，乙原則上不須負損害賠償責任", "甲客觀上是為乙服勞務之人，故乙必須負損害賠償責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00145', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '出租人甲與承租人乙訂立A車租賃契約，於下列何種情形，乙有權占有A車？', '["甲交付A車於乙使用", "租期屆滿後，乙拒絕返還", "租賃無效", "乙自行占有A車"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00146', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲將其所有之鑽錶寄託於乙處。乙以自己名義，出售並交付於不知情且無重大過失之丙。下列敘 述，何者正確？', '["甲得隨時向丙請求返還鑽錶", "甲僅得於2年內向丙請求返還鑽錶", "甲於償還丙支付之價金後，得向丙請求返還鑽錶，甲所受損害再向乙請求", "甲不得向丙請求返還鑽錶，甲所受損害僅得向乙請求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00147', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲男、乙女於民國110年5月間結婚，結婚後依法約定採分別財產制。下列敘述，何者正確？', '["甲、乙之一方在婚姻關係存續當中，就其婚後財產所為之無償行為，有害及他方之剩餘財產差 額分配請求權者，他方得於知有撤銷原因時起1年間，或自行為時起2年內，聲請法院撤銷上開 無償行為", "甲、乙財產制關係消滅時，其夫妻現存之婚後財產，應平均分配。平均分配顯失公平者，法院 得調整或免除其分配額", "甲、乙之一方以自己財產清償他方之債務時，雖於婚姻關係存續中，亦得請求他方償還", "甲、乙之一方依法應給付家庭生活費用而不給付時，法院因他方之請求，得宣告改用共同財產制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00148', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '關於父母對未成年子女親權之行使與禁止，下列敘述，何者正確？', '["未成年子女之特有財產，父母應以家庭生活之共同利益，而使用、收益、處分之。但子女已滿 16歲者，應得其書面同意", "父母之一方濫用其對於子女之權利時，法院得依他方、未成年子女、主管機關或其他利害關係 人之請求，為子女之利益，宣告停止其權利之全部或一部", "未成年子女之特有財產，由父母共同管理。但父母分居、或養子女與養父母合意終止收養經撤 銷者，不在此限", "父母未共同生活達6個月以上時，關於未成年子女之會面交往權之行使，父母、祖父母或社福機 構均得聲請法院酌定之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00149', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-9b7ab1bb', 'sub-heelevel3-53250add-02', NULL, 'single_choice', '甲重男輕女，因子丁留學美國，將其財產新臺幣（下同）1,000萬元贈與丁，完全不顧及平日照顧 其生活起居之妻乙及女丙之感受。1年後，甲死亡，另遺有財產600萬元，丙得繼承多少財產？', '["1,000萬元", "500萬元", "200萬元", "125萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00150', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'essay', '甲為某大樓之頂樓層7樓住戶，於民國80年間在其與樓下住戶間之樓梯間
（即6樓至7樓間）裝設鐵門，以阻擋其他住戶出入大樓頂樓陽台。嗣民國
84年6月9日公寓大廈管理條例制定，於第16條第2項規定：「住戶不得於防
火間隔、防火巷弄、樓梯間、共同走廊、防空避難設備等處所堆置雜物、
設置柵欄、門扇或營業使用，或違規設置廣告物或私設路障及停車位侵佔
巷道妨礙出入。」該條項於92年12月9日修正為：「住戶不得於私設通路、
防火間隔、防火巷弄、開放空間、退縮空地、樓梯間、共同走廊、防空避
難設備等處所堆置雜物、設置柵欄、門扇或營業使用，或違規設置廣告物
或私設路障及停車位侵占巷道妨礙出入。」適用迄今。乙於112年6月間遷
入同大樓，為甲之樓下（6樓）鄰居，見甲有於樓梯間擅設鐵門，妨礙出
入之違章情事，遂向地方主管機關丙檢舉。請問：
丙得否依現行公寓大廈管理條例第49條第1項規定：「有下列行為之一
者，由直轄市、縣（市）主管機關處新臺幣四萬元以上二十萬元以下罰
鍰，並得令其限期改善或履行義務；屆期不改善或不履行者，得連續處
罰：……四、住戶違反第十六條第二項或第三項規定者。」對甲80年間
於樓梯間設置鐵門之行為處以罰鍰？（20分）
在子題答案為肯定之假設前提下，若甲經丙命限期改善，屆期不改
善，丙依上開條項規定，得連續處罰之。從確保住戶安全之觀點出發，
丙在法制上除連續處罰外，是否尚有其他手段可資採行？其與連續處
罰間之選擇，應為如何之合義務裁量？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4bc34ba84b99", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00151', 'heelevel3-53250add', 'heelevel3-53250add-moex-112-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'essay', '甲原為乙市立國民中學丙校之教師，民國112年5月某日於督導導生清掃
校園時，因丁生與同學嬉戲，甲見狀上前，以清潔用具頂撞丁生腹部，致
丁生腹部出血，緊急送醫。嗣丙校召開教師評審委員會（以下簡稱教評
會），決議甲之行為該當教師法第15條第1項第3款「體罰或霸凌學生，造
成其身心侵害，有解聘之必要」之規定，應予解聘，並依同條項序文規定，
決議甲4年不得聘任為教師。上開丙校教評會之決議續依法定程序，報經
乙市政府核准在案。甲不服，可向行政法院為如何之權利救濟？（20分）
33650
參考條文：
教師法
第15條第1項：「教師有下列各款情形之一者，應予解聘，且應議決一年至四年不得
聘任為教師：……三、體罰或霸凌學生，造成其身心侵害，有解聘之必要。」
第19條第1項：「有下列各款情形之一者，不得聘任為教師；已聘任者，應予以解
聘：……二、有第十五條第一項各款情形之一，於該議決一年至四年期間。」
第26條第1項：「學校教師評審委員會、性別平等教育委員會或依法組成之相關委員
會依第十四條至第十六條規定作成教師解聘或不續聘之決議，或依第十八條規定作
成教師終局停聘之決議後，除本法另有規定外，學校應自決議作成之日起十日內報
主管機關核准，並同時以書面附理由通知當事人。」
第2條第1項：「本法所稱主管機關：在中央為教育部；在直轄市為直轄市政府；在縣
（市）為縣（市）政府。」', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:04+00:00", "source_pdf_sha1": "4bc34ba84b99", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "336", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL)
